qry:select.qry:xquery:
					for $r in sql('
				SELECT ORG19_LOCALIDADES.oi_localidad as oi_localidad 
				{%? (#SOURCE:@ATRIB_ORDEN1!='')	{% ,ORG19_LOCALIDADES.{%=#SOURCE:@ATRIB_ORDEN1%} %} {% %} %}     	 	
				FROM ORG19_LOCALIDADES
				WHERE 1=1 
			 	{%? (#SOURCE:@oi_provincia!='')	{% AND ORG19_LOCALIDADES.oi_provincia={#SOURCE:@oi_provincia} %} {% %} %}
			 	{%? (#SOURCE:@oi_municipio!='')	{% AND ORG19_LOCALIDADES.oi_municipio={#SOURCE:@oi_municipio} %} {% %} %}
 		 	 	{%? (string(#SOURCE:LOCALIDADES/LOCALIDAD/@id)!='') {% AND ORG19_LOCALIDADES.oi_localidad IN ({%=string(#SOURCE:LOCALIDADES/LOCALIDAD/@id) %}) %} {%  %} %}
				ORDER BY
    		{%? (#SOURCE:@ATRIB_ORDEN1!='')	{% {%=#SOURCE:@ATRIB_ORDEN1%} {%? (#SOURCE:@ORDEN1!='') {% {%=#SOURCE:@ORDEN1%}, %} {% ASC, %}	%} %} {% %} %}     	 	
     		oi_localidad Asc
			')/ROWS/ROW
